// ============================================
// NORMALIZE INPUT
// Purpose: Clean and prepare input for processing
// ============================================

const input = $input.first().json;

// --- Helper Functions ---

// Check if text contains Arabic characters
function containsArabic(text) {
  const arabicPattern = /[\u0600-\u06FF\u0750-\u077F\u08A0-\u08FF]/;
  return arabicPattern.test(text);
}

// Remove Arabic diacritics (tashkeel)
function removeArabicDiacritics(text) {
  return text.replace(/[\u064B-\u065F\u0670]/g, '');
}

// Normalize Arabic letters (alef, yeh variations)
function normalizeArabic(text) {
  return text
    .replace(/[\u0622\u0623\u0625]/g, '\u0627') // Normalize alef
    .replace(/[\u0649]/g, '\u064A') // Normalize yeh
    .replace(/[\u0629]/g, '\u0647'); // Normalize teh marbuta
}

// --- Extract and Validate Input ---

const sessionId = input.session_id || `session_${Date.now()}`;
const channel = ['chat', 'voice', 'whatsapp'].includes(input.channel) ? input.channel : 'chat';
let userMessage = (input.user_message || '').trim();
const metadata = input.metadata || {};

// --- Detect Language ---

let language = input.language;
if (!language || !['ar', 'en'].includes(language)) {
  language = containsArabic(userMessage) ? 'ar' : 'en';
}

// --- Normalize Message ---

let normalizedMessage = userMessage;

if (language === 'ar') {
  // Arabic normalization
  normalizedMessage = removeArabicDiacritics(normalizedMessage);
  normalizedMessage = normalizeArabic(normalizedMessage);
} else {
  // English normalization
  normalizedMessage = normalizedMessage.toLowerCase();
}

// --- Increment Conversation Turn ---

const conversationTurn = (metadata.conversation_turn || 0) + 1;

// --- Build Output ---

const output = {
  session_id: sessionId,
  channel: channel,
  language: language,
  user_message: userMessage,
  normalized_message: normalizedMessage,
  metadata: {
    phone: metadata.phone || null,
    name: metadata.name || null,
    previous_intent: metadata.previous_intent || null,
    conversation_turn: conversationTurn,
    customer_sentiment: metadata.customer_sentiment || 'neutral'
  },
  timestamp: new Date().toISOString()
};

return { json: output };

// ============================================
// DETECT INTENT
// Purpose: Classify user intent using keyword matching
// Priority: COMPLAINT > HUMAN_REQUEST > WARRANTY > SALES_PRICE > SALES_RECOMMENDATION > DELIVERY > GENERAL_SUPPORT
// ============================================

const input = $input.first().json;
const message = input.normalized_message || '';
const language = input.language || 'ar';

// --- Intent Definitions (Priority Order) ---

const intents = [
  {
    intent: 'COMPLAINT',
    priority: 1,
    target_agent: 'complaint',
    keywords_ar: ['شكوى', 'مشكلة', 'زعلان', 'مش راضي', 'سيء', 'وحش', 'اسوء', 'عايز فلوسي', 'استرجاع', 'ندمان', 'غلط', 'كذب', 'نصب', 'خدعة'],
    keywords_en: ['complaint', 'problem', 'angry', 'not satisfied', 'bad', 'terrible', 'worst', 'refund', 'return', 'regret', 'wrong', 'lied', 'scam', 'fraud']
  },
  {
    intent: 'HUMAN_REQUEST',
    priority: 2,
    target_agent: 'escalation',
    keywords_ar: ['عايز اتكلم مع حد', 'حد يرد', 'موظف', 'خدمة عملاء', 'بني ادم', 'حد حقيقي', 'مدير', 'مسؤول', 'مش فاهم', 'مش بتفهم'],
    keywords_en: ['talk to someone', 'speak to agent', 'human', 'customer service', 'real person', 'manager', 'supervisor', 'representative', 'dont understand']
  },
  {
    intent: 'WARRANTY',
    priority: 3,
    target_agent: 'warranty',
    keywords_ar: ['ضمان', 'مدة الضمان', 'تفعيل الضمان', 'شهادة ضمان', 'تصليح', 'صيانة', 'عيب صناعة', 'الضمان ساري', 'انتهى الضمان'],
    keywords_en: ['warranty', 'guarantee', 'activate warranty', 'warranty certificate', 'repair', 'maintenance', 'defect', 'warranty valid', 'warranty expired']
  },
  {
    intent: 'SALES_PRICE',
    priority: 4,
    target_agent: 'sales',
    keywords_ar: ['سعر', 'بكام', 'كام', 'تكلفة', 'عروض', 'خصم', 'تقسيط', 'اسعار'],
    keywords_en: ['price', 'cost', 'how much', 'offers', 'discount', 'installment', 'pricing']
  },
  {
    intent: 'SALES_RECOMMENDATION',
    priority: 5,
    target_agent: 'sales',
    keywords_ar: ['عايز اشتري', 'عايز مرتبة', 'انصحني', 'ايه احسن', 'افضل', 'اختار', 'مقاسات', 'انواع', 'منتجات'],
    keywords_en: ['buy', 'purchase', 'recommend', 'suggest', 'best', 'which one', 'sizes', 'types', 'products', 'mattress']
  },
  {
    intent: 'DELIVERY',
    priority: 6,
    target_agent: 'support',
    keywords_ar: ['توصيل', 'شحن', 'يوصل امتى', 'مدة التوصيل', 'رسوم الشحن', 'مصاريف الشحن'],
    keywords_en: ['delivery', 'shipping', 'when arrive', 'delivery time', 'shipping cost', 'shipping fee']
  },
  {
    intent: 'GENERAL_SUPPORT',
    priority: 7,
    target_agent: 'support',
    keywords_ar: ['فين الفرع', 'عنوان', 'مواعيد', 'رقم التليفون', 'سؤال', 'استفسار', 'معلومات', 'ازاي', 'فروع'],
    keywords_en: ['store location', 'address', 'working hours', 'phone number', 'question', 'inquiry', 'information', 'how to', 'branches']
  }
];

// --- Keyword Matching ---

let detectedIntent = 'GENERAL_SUPPORT';
let targetAgent = 'support';
let matchedKeywords = [];
let maxMatches = 0;
let confidenceScore = 0.5; // Default for fallback

for (const intentDef of intents) {
  const keywords = language === 'ar' ? intentDef.keywords_ar : intentDef.keywords_en;
  const matches = [];

  for (const keyword of keywords) {
    if (message.includes(keyword.toLowerCase())) {
      matches.push(keyword);
    }
  }

  if (matches.length > 0) {
    // First match wins (priority order)
    detectedIntent = intentDef.intent;
    targetAgent = intentDef.target_agent;
    matchedKeywords = matches;
    confidenceScore = Math.min(0.95, 0.5 + (matches.length * 0.15));
    break; // Stop at first match (priority-based)
  }
}

// --- Check for Immediate Escalation Triggers ---

const legalKeywords = language === 'ar' 
  ? ['محامي', 'قانون', 'شرطة', 'نيابة', 'قضية']
  : ['lawyer', 'legal', 'police', 'sue', 'court'];

const mediaKeywords = language === 'ar'
  ? ['هنشر', 'فيسبوك', 'سوشيال', 'جرنال', 'تويتر']
  : ['post', 'facebook', 'social media', 'twitter', 'review'];

let forceEscalation = false;
let escalationReason = null;

for (const kw of legalKeywords) {
  if (message.includes(kw.toLowerCase())) {
    forceEscalation = true;
    escalationReason = 'legal_threat';
    break;
  }
}

if (!forceEscalation) {
  for (const kw of mediaKeywords) {
    if (message.includes(kw.toLowerCase())) {
      forceEscalation = true;
      escalationReason = 'media_threat';
      break;
    }
  }
}

if (forceEscalation) {
  detectedIntent = 'HUMAN_REQUEST';
  targetAgent = 'escalation';
  confidenceScore = 1.0;
}

// --- Build Output ---

const output = {
  ...input,
  intent: {
    detected: detectedIntent,
    confidence: confidenceScore,
    matched_keywords: matchedKeywords
  },
  target_agent: targetAgent,
  force_escalation: forceEscalation,
  escalation_reason: escalationReason
};

return { json: output };

// ============================================
// EXECUTE SALES AGENT
// Purpose: Handle pricing, recommendations, product info
// ============================================

const input = $input.first().json;
const language = input.language || 'ar';
const intent = input.intent?.detected || 'SALES_PRICE';
const message = input.normalized_message || '';

// --- Sales Agent Configuration ---

const tone = {
  ar: 'Egyptian Arabic, confident, persuasive but polite',
  en: 'Professional, friendly, sales-oriented'
};

// --- PLACEHOLDER: Database Queries ---
// In production, fetch from PostgreSQL:
// - products table
// - prices table
// - promotions table

const sampleProducts = [
  {
    id: 'prod_001',
    name_ar: 'مرتبة يانسن أورثوبيديك',
    name_en: 'Janssen Orthopedic Mattress',
    price: 12500,
    currency: 'EGP',
    warranty_years: 10
  },
  {
    id: 'prod_002',
    name_ar: 'مرتبة يانسن ميموري فوم',
    name_en: 'Janssen Memory Foam Mattress',
    price: 15000,
    currency: 'EGP',
    warranty_years: 12
  }
];

// --- Generate Response ---

let responseText = '';
let responseType = 'text';
let productCard = null;
let escalationRequired = false;

if (intent === 'SALES_PRICE') {
  // Price inquiry response
  if (language === 'ar') {
    responseText = `تمام! أسعار المراتب عندنا بتبدأ من ${sampleProducts[0].price.toLocaleString()} جنيه. عندنا موديلات مختلفة:\n\n`;
    responseText += `- ${sampleProducts[0].name_ar}: ${sampleProducts[0].price.toLocaleString()} جنيه (ضمان ${sampleProducts[0].warranty_years} سنين)\n`;
    responseText += `- ${sampleProducts[1].name_ar}: ${sampleProducts[1].price.toLocaleString()} جنيه (ضمان ${sampleProducts[1].warranty_years} سنة)\n\n`;
    responseText += 'عايز تعرف تفاصيل أكتر عن موديل معين؟';
  } else {
    responseText = `Great! Our mattress prices start from ${sampleProducts[0].price.toLocaleString()} EGP. We have different models:\n\n`;
    responseText += `- ${sampleProducts[0].name_en}: ${sampleProducts[0].price.toLocaleString()} EGP (${sampleProducts[0].warranty_years}-year warranty)\n`;
    responseText += `- ${sampleProducts[1].name_en}: ${sampleProducts[1].price.toLocaleString()} EGP (${sampleProducts[1].warranty_years}-year warranty)\n\n`;
    responseText += 'Would you like more details about a specific model?';
  }
} else if (intent === 'SALES_RECOMMENDATION') {
  // Recommendation response with product card
  responseType = 'product_card';
  const product = sampleProducts[0];

  if (language === 'ar') {
    responseText = 'بناءً على احتياجاتك، أنصحك بالمرتبة دي:';
  } else {
    responseText = 'Based on your needs, I recommend this mattress:';
  }

  productCard = {
    id: product.id,
    name: language === 'ar' ? product.name_ar : product.name_en,
    description: language === 'ar' 
      ? 'مرتبة طبية عالية الجودة مع دعم ممتاز للظهر'
      : 'Premium orthopedic mattress with excellent back support',
    price: `${product.price.toLocaleString()} ${product.currency}`,
    warranty: `${product.warranty_years} ${language === 'ar' ? 'سنين ضمان' : 'years warranty'}`,
    image_url: 'PLACEHOLDER_IMAGE_URL'
  };
} else {
  // Default sales response
  if (language === 'ar') {
    responseText = 'أهلاً! أنا هنا أساعدك تختار المرتبة المناسبة ليك. عايز تعرف عن الأسعار ولا عايز نصيحة؟';
  } else {
    responseText = 'Hello! I\'m here to help you choose the right mattress. Would you like to know about prices or get a recommendation?';
  }
}

// --- Check for Bulk Order (requires escalation) ---

const bulkKeywords = language === 'ar' 
  ? ['جملة', 'كمية', 'شركة', 'فندق', 'مستشفى']
  : ['bulk', 'wholesale', 'company', 'hotel', 'hospital'];

for (const kw of bulkKeywords) {
  if (message.includes(kw)) {
    escalationRequired = true;
    break;
  }
}

// --- Build Output ---

const output = {
  ...input,
  agent_used: 'sales',
  response_type: responseType,
  content: {
    text: responseText,
    product: productCard
  },
  escalation_required: escalationRequired,
  actions_taken: ['FETCH_PRODUCT', 'FETCH_PRICE']
};

return { json: output };

// ============================================
// EXECUTE SUPPORT AGENT
// Purpose: Handle delivery, locations, FAQs, general support
// ============================================

const input = $input.first().json;
const language = input.language || 'ar';
const intent = input.intent?.detected || 'GENERAL_SUPPORT';
const message = input.normalized_message || '';

// --- Support Agent Configuration ---

const tone = {
  ar: 'Egyptian Arabic, calm and reassuring',
  en: 'Clear, calm, and helpful'
};

// --- PLACEHOLDER: Database Queries ---
// In production, fetch from PostgreSQL:
// - delivery_rules table
// - store_locations table
// - faq_database

const deliveryInfo = {
  cairo_giza: {
    ar: 'القاهرة والجيزة: التوصيل خلال 2-3 أيام عمل',
    en: 'Cairo & Giza: Delivery within 2-3 business days'
  },
  alexandria: {
    ar: 'الإسكندرية: التوصيل خلال 3-5 أيام عمل',
    en: 'Alexandria: Delivery within 3-5 business days'
  },
  other: {
    ar: 'باقي المحافظات: التوصيل خلال 5-7 أيام عمل',
    en: 'Other governorates: Delivery within 5-7 business days'
  },
