} else if (message.includes(language === 'ar' ? 'مواعيد' : 'hours') ||
           message.includes(language === 'ar' ? 'ساعات' : 'time')) {
  // Working hours inquiry
  if (language === 'ar') {
    responseText = 'مواعيد العمل:\n• أيام الأسبوع: من 9 الصبح لـ 9 بالليل\n• الجمعة والسبت: من 10 الصبح لـ 6 بالليل\n\nمحتاج حاجة تانية؟';
  } else {
