  }
}

// --- Check for Complex Issues (may require escalation) ---

const complexKeywords = language === 'ar'
  ? ['تأخير', 'متأخر', 'فين الطلب', 'مش واصل']
  : ['delayed', 'late', 'where is my order', 'not arrived'];

for (const kw of complexKeywords) {
  if (message.includes(kw)) {
    escalationRequired = true;
    break;
  }
}

// --- Build Output ---

const output = {
  ...input,
  agent_used: 'support',
  response_type: 'text',
  content: {
    text: responseText,
    product: null
  },
  escalation_required: escalationRequired,
