// ============================================
// EXECUTE WARRANTY AGENT
// Purpose: Explain warranty policies, guide activation, collect claim details
// NEVER approve or reject warranty claims
// ============================================

const input = $input.first().json;
const language = input.language || 'ar';
const message = input.normalized_message || '';

// --- Warranty Agent Configuration ---

const tone = {
  ar: 'Egyptian Arabic, professional and understanding',
  en: 'Professional, empathetic, informative'
};

// --- PLACEHOLDER: Database Queries ---
// In production, fetch from PostgreSQL:
// - warranty_policies table
// - product_warranty_terms table

const warrantyPolicy = {
  standard: {
    duration_years: 10,
    covers_ar: 'عيوب الصناعة، تهالك السوست، انخفاض المرتبة أكتر من 3 سم',
    covers_en: 'Manufacturing defects, spring deterioration, sagging more than 3cm',
    excludes_ar: 'سوء الاستخدام، البقع، الحرق، التلف المتعمد',
    excludes_en: 'Misuse, stains, burns, intentional damage'
  }
};

// --- Generate Response ---

let responseText = '';
let escalationRequired = false;

// Check if this is a claim request
const claimKeywords = language === 'ar'
  ? ['عايز اقدم', 'طلب ضمان', 'استبدال', 'تغيير']
  : ['file claim', 'warranty claim', 'replace', 'exchange'];

const isClaimRequest = claimKeywords.some(kw => message.includes(kw));

if (isClaimRequest) {
  // Warranty claim - collect details then escalate
  if (language === 'ar') {
    responseText = 'تمام، هساعدك في موضوع الضمان. علشان نقدر نفتحلك طلب، هحتاج منك:\n\n';
    responseText += '1. رقم الفاتورة\n';
    responseText += '2. تاريخ الشراء\n';
    responseText += '3. وصف المشكلة\n\n';
    responseText += 'لو معاك البيانات دي، ابعتهالي وهحولك لقسم الضمان.';
  } else {
    responseText = 'Sure, I\'ll help you with the warranty. To file a claim, I\'ll need:\n\n';
    responseText += '1. Invoice number\n';
    responseText += '2. Purchase date\n';
    responseText += '3. Description of the issue\n\n';
    responseText += 'If you have this information, please share it and I\'ll connect you with our warranty department.';
  }
  // Claims always escalate after collecting details
  escalationRequired = true;

} else if (message.includes(language === 'ar' ? 'بيغطي' : 'cover') ||
           message.includes(language === 'ar' ? 'شامل' : 'include')) {
  // What does warranty cover
  if (language === 'ar') {
    responseText = `ضمان يانسن ${warrantyPolicy.standard.duration_years} سنين بيغطي:\n\n`;
    responseText += `✅ ${warrantyPolicy.standard.covers_ar}\n\n`;
    responseText += `❌ الضمان مش بيشمل: ${warrantyPolicy.standard.excludes_ar}\n\n`;
    responseText += 'عندك سؤال تاني عن الضمان؟';
  } else {
    responseText = `Janssen ${warrantyPolicy.standard.duration_years}-year warranty covers:\n\n`;
    responseText += `✅ ${warrantyPolicy.standard.covers_en}\n\n`;
    responseText += `❌ Warranty excludes: ${warrantyPolicy.standard.excludes_en}\n\n`;
    responseText += 'Do you have any other warranty questions?';
  }

} else if (message.includes(language === 'ar' ? 'تفعيل' : 'activate')) {
  // Warranty activation
  if (language === 'ar') {
    responseText = 'لتفعيل الضمان:\n\n';
    responseText += '1. احتفظ بالفاتورة الأصلية\n';
    responseText += '2. سجل المنتج خلال 30 يوم من الشراء\n';
    responseText += '3. تواصل معانا لو حصلت أي مشكلة\n\n';
    responseText += 'الضمان بيبدأ من تاريخ الفاتورة تلقائياً.';
  } else {
    responseText = 'To activate warranty:\n\n';
    responseText += '1. Keep your original invoice\n';
    responseText += '2. Register product within 30 days of purchase\n';
    responseText += '3. Contact us if any issues arise\n\n';
    responseText += 'Warranty starts automatically from the invoice date.';
  }

} else {
  // Default warranty response
  if (language === 'ar') {
    responseText = `أهلاً! الضمان بتاع يانسن ${warrantyPolicy.standard.duration_years} سنين وبيغطي عيوب الصناعة.\n\n`;
    responseText += 'عايز تعرف إيه اللي الضمان بيغطيه، ولا عايز تفعل الضمان، ولا عندك مشكلة في المنتج؟';
  } else {
    responseText = `Hello! Janssen warranty is ${warrantyPolicy.standard.duration_years} years and covers manufacturing defects.\n\n`;
    responseText += 'Would you like to know what\'s covered, how to activate warranty, or do you have an issue with your product?';
  }
}

// --- Build Output ---

const output = {
  ...input,
  agent_used: 'warranty',
  response_type: 'text',
  content: {
    text: responseText,
    product: null
  },
  escalation_required: escalationRequired,
  actions_taken: ['FETCH_WARRANTY_POLICY', 'EXPLAIN_WARRANTY_TERMS']
};

return { json: output };

// ============================================
// EXECUTE COMPLAINT AGENT
// Purpose: Handle complaints with empathy, de-escalate, collect details
// NEVER dismiss, argue, or promise refunds
// ALL complaints eventually escalate to human
// ============================================

const input = $input.first().json;
const language = input.language || 'ar';
const message = input.normalized_message || '';
const conversationTurn = input.metadata?.conversation_turn || 1;

// --- Complaint Agent Configuration ---

const tone = {
  ar: 'Egyptian Arabic, deeply empathetic, apologetic',
  en: 'Empathetic, apologetic, patient'
};

// --- De-escalation Phrases ---

const empathyPhrases = {
  ar: [
    'معلش جداً على اللي حصل',
    'فاهم زعلك وحقك عليا تماماً',
    'أنا هنا علشان أساعدك',
    'رأيك مهم جداً لينا'
  ],
  en: [
    'I\'m truly sorry about what happened',
    'I completely understand your frustration',
    'I\'m here to help you',
    'Your feedback is very important to us'
  ]
};

// --- Generate Response ---

let responseText = '';

// First turn: Acknowledge with empathy
if (conversationTurn <= 2) {
  if (language === 'ar') {
    responseText = `${empathyPhrases.ar[0]}. ${empathyPhrases.ar[1]}.\n\n`;
    responseText += 'علشان أقدر أساعدك، ممكن تقولي:\n';
    responseText += '1. إيه اللي حصل بالظبط؟\n';
    responseText += '2. امتى ده حصل؟\n';
    responseText += '3. رقم الفاتورة لو معاك؟\n\n';
    responseText += 'كل المعلومات دي هتساعدني أحل الموضوع معاك.';
  } else {
    responseText = `${empathyPhrases.en[0]}. ${empathyPhrases.en[1]}.\n\n`;
