// RESPONSE FORMATTER
// Purpose: Format response for specific channel
// ============================================

const input = $input.first().json;
const channel = input.channel || 'chat';
const language = input.language || 'ar';

let formattedContent = { ...input.content };
let responseText = input.content?.text || '';

// --- Channel-Specific Formatting ---

if (channel === 'voice') {
  // Voice: Short text, no emojis, SSML-ready
  responseText = responseText
    .replace(/[\u{1F600}-\u{1F64F}]/gu, '') // Remove emojis
    .replace(/[\u{1F300}-\u{1F5FF}]/gu, '')
    .replace(/[\u{1F680}-\u{1F6FF}]/gu, '')
    .replace(/[\u{2600}-\u{26FF}]/gu, '')
    .replace(/[\u{2700}-\u{27BF}]/gu, '')
    .replace(/\n+/g, '. ') // Replace newlines with periods
    .replace(/•/g, ',') // Replace bullets
    .replace(/✅/g, '')
    .replace(/❌/g, '')
    .trim();

  // Truncate for voice
  if (responseText.length > 200) {
    responseText = responseText.substring(0, 197) + '...';
  }

  formattedContent = {
    text: responseText,
    ssml: `<speak>${responseText}</speak>`
  };

} else if (channel === 'whatsapp') {
  // WhatsApp: Template-ready format
  formattedContent = {
    text: responseText,
    template_ready: true,
    interactive: input.response_type === 'product_card' ? {
      type: 'product',
      body: responseText,
      product: input.content?.product
    } : null
  };

} else {
  // Chat: Rich format with HTML support
  formattedContent = {
    text: responseText,
    html: responseText.replace(/\n/g, '<br>'),
    product_card: input.content?.product || null
  };
}

// --- Build Final Output ---

const output = {
  session_id: input.session_id,
  channel: channel,
  language: language,
  response_type: input.response_type || 'text',
  content: formattedContent,
  next_action: 'await_response',
  agent_used: input.agent_used,
  confidence_score: input.intent?.confidence || 0.5,
  metadata: {
    intent_detected: input.intent?.detected,
    actions_taken: input.actions_taken,
    timestamp: new Date().toISOString()
  }
};

return { json: output };

